/*
 * Example 3: Search Row-Column Sorted Matrix
 */
#include <bits/stdc++.h>
using namespace std;
bool searchSorted2D(vector<vector<int>>&m,int t){
    int r=0,c=(int)m[0].size()-1;
    while(r<(int)m.size()&&c>=0){if(m[r][c]==t)return true;else if(m[r][c]>t)c--;else r++;}
    return false;
}
